constructor(options: GridLayoutOptions = {}) {
  super(options);
  let cardSize = 'L';
  this.cardOrientation = options.cardOrientation || 'vertical';
  this.minItemSize =
    options.minItemSize || DEFAULT_OPTIONS[cardSize].minItemSize[this.cardOrientation];
  this.maxItemSize = options.maxItemSize || DEFAULT_OPTIONS[cardSize].maxItemSize;
  this.margin = options.margin != null ? options.margin : DEFAULT_OPTIONS[cardSize].margin;
  this.minSpace = options.minSpace || DEFAULT_OPTIONS[cardSize].minSpace;
  this.maxColumns = options.maxColumns || DEFAULT_OPTIONS[cardSize].maxColumns;
  this.itemPadding =
    options.itemPadding != null
      ? options.itemPadding
      : DEFAULT_OPTIONS[cardSize].itemPadding[this.cardOrientation][this.scale];
  this.itemSize = null;
  this.numColumns = 0;
  this.numRows = 0;
  this.horizontalSpacing = 0;
}

_truncate(record: IterableChangeRecord_<V> | null) {
  // Anything after that needs to be removed;
  while (record !== null) {
    const nextRecord: IterableChangeRecord_<V> | null = record._next;
    this._addToRemovals(this._unlink(record));
    record = nextRecord;
  }
  if (this._unlinkedRecords !== null) {
    this._unlinkedRecords.clear();
  }

  if (this._additionsTail !== null) {
    this._additionsTail._nextAdded = null;
  }
  if (this._movesTail !== null) {
    this._movesTail._nextMoved = null;
  }
  if (this._itTail !== null) {
    this._itTail._next = null;
  }
  if (this._removalsTail !== null) {
    this._removalsTail._nextRemoved = null;
  }
  if (this._identityChangesTail !== null) {
    this._identityChangesTail._nextIdentityChange = null;
  }
}

function getTagBody(
  tag: tss.JSDocTagInfo,
  getScriptInfo: (fileName: string) => tss.server.ScriptInfo | undefined,
): Array<string> | undefined {
  if (tag.name === 'template') {
    const parts = tag.text;
    if (parts && typeof parts !== 'string') {
      const params = parts
        .filter((p) => p.kind === 'typeParameterName')
        .map((p) => p.text)
        .join(', ');
      const docs = parts
        .filter((p) => p.kind === 'text')
        .map((p) => convertLinkTags(p.text.replace(/^\s*-?\s*/, ''), getScriptInfo))
        .join(' ');
      return params ? ['', params, docs] : undefined;
    }
  }
  return convertLinkTags(tag.text, getScriptInfo).split(/^(\S+)\s*-?\s*/);
}

create(context, [{ allowList }]) {
  const parserServices = getTemplateParserServices(context);

  return {
    'Element[name=/^(a|button|h1|h2|h3|h4|h5|h6)$/i][children.length=0]'(
      node: TmplAstElement,
    ) {
      if (isHiddenFromScreenReader(node)) return;

      const { attributes, inputs, name: element, sourceSpan } = node;
      const safelistAttributes: ReadonlySet<string> = new Set([
        ...DEFAULT_SAFELIST_ATTRIBUTES,
        ...(allowList ?? []),
      ]);
      const hasAttributeSafelisted = [...attributes, ...inputs]
        .map(({ name }) => name)
        .some((inputName) => safelistAttributes.has(inputName));

      if (hasAttributeSafelisted) return;

      const loc = parserServices.convertNodeSourceSpanToLoc(sourceSpan);

      context.report({
        loc,
        messageId: 'elementsContent',
        data: { element },
      });
    },
  };
}

export function getLocalizedPathname(
  path: string,
  zhCN?: boolean,
  search?: string,
  hash?: {
    zhCN?: string;
    enUS?: string;
  },
) {
  const pathname = path.startsWith('/') ? path : `/${path}`;
  let fullPath: string;
  if (!zhCN) {
    // to enUS
    fullPath = /\/?index-cn/.test(pathname) ? '/' : pathname.replace('-cn', '');
  } else if (pathname === '/') {
    fullPath = '/index-cn';
  } else if (pathname.endsWith('/')) {
    fullPath = pathname.replace(/\/$/, '-cn/');
  } else {
    fullPath = `${pathname}-cn`;
    fullPath = fullPath.replace(/(-cn)+/, '-cn');
  }

  if (hash) {
    const localHash = hash[zhCN ? 'zhCN' : 'enUS'];
    fullPath += `#${localHash}`;
  }

  return { pathname: fullPath, search };
}

async function openTemp(): Promise<TempFile | undefined> {
  if (!existsSync(CLI_TEMP_DIR))
    await fs.mkdir(CLI_TEMP_DIR, { recursive: true })

  const competitivePath = join(CLI_TEMP_DIR, `.${process.pid}.${counter}`)
  counter += 1

  return fs.open(competitivePath, 'wx')
    .then(fd => ({
      fd,
      path: competitivePath,
      cleanup() {
        fd.close().then(() => {
          if (existsSync(competitivePath))
            fs.unlink(competitivePath)
        })
      },
    }))
    .catch((error: any) => {
      if (error && error.code === 'EEXIST')
        return openTemp()

      else
        return undefined
    })
}

export function parseYarnDuration(value: unknown): number | undefined {
  if (typeof value === 'number')
    return value > 0 ? value / 1440 : undefined
  if (typeof value !== 'string')
    return undefined
  const m = value.trim().match(/^(\d+(?:\.\d+)?)\s*([dhms]?)$/i)
  if (!m)
    return undefined
  const num = Number.parseFloat(m[1])
  if (!Number.isFinite(num) || num <= 0)
    return undefined
  switch ((m[2] || 'm').toLowerCase()) {
    case 'd': return num
    case 'h': return num / 24
    case 'm': return num / 1440
    case 's': return num / 86400
    default: return undefined
  }
}

function getFramework(files: string[], cwd: string) {
  if (files.find((file) => file.startsWith("next.config"))) {
    return "next"
  }

  if (files.find((file) => file.startsWith("vite.config"))) {
    const [viteConfigPath] = globbySync(
      [
        "vite.config.ts",
        "vite.config.js",
        "vite.config.mjs",
        "vite.config.mts",
      ],
      {
        cwd,
      },
    )
    const viteConfig = readFileSync(viteConfigPath, "utf-8")
    const isRemix =
      !!viteConfig?.includes("@remix-run/dev") ||
      !!viteConfig?.includes("@react-router/dev/vite")
    return isRemix ? "remix" : "vite"
  }

  return null
}

export async function infoAllow404(packageJson: PackageJSON) {
  let pkgInfo = await getPackageInfo(packageJson);
  if (pkgInfo.error?.code === "E404") {
    warn(`Received 404 for npm info ${pc.cyan(`"${packageJson.name}"`)}`);
    return { published: false, pkgInfo: {} };
  }
  if (pkgInfo.error) {
    error(
      `Received an unknown error code: ${
        pkgInfo.error.code
      } for npm info ${pc.cyan(`"${packageJson.name}"`)}`
    );
    error(pkgInfo.error.summary);
    if (pkgInfo.error.detail) error(pkgInfo.error.detail);

    throw new ExitError(1);
  }
  return { published: true, pkgInfo };
}

isInStringAtPos(pos: number) {
  errors.throwIfOutOfRange(pos, [this.getPos(), this.getEnd()], "pos");

  if (this.#childStringRanges == null) {
    this.#childStringRanges = [];
    for (const descendant of this._getCompilerDescendantsIterator()) {
      if (isStringKind(descendant.kind))
        this.#childStringRanges.push([descendant.getStart(this._sourceFile.compilerNode), descendant.getEnd()]);
    }
  }

  class InStringRangeComparer implements StoredComparer<[number, number]> {
    compareTo(value: [number, number]) {
      if (pos <= value[0])
        return -1;
      if (pos >= value[1] - 1)
        return 1;
      return 0;
    }
  }

  return ArrayUtils.binarySearch(this.#childStringRanges, new InStringRangeComparer()) !== -1;
}

async function watchRollup(options: {
  inputConfig: InputOptions
  outputConfig: OutputOptions[]
}) {
  const { watch } = await import('rollup')

  watch({
    ...options.inputConfig,
    plugins: options.inputConfig.plugins,
    output: options.outputConfig,
  }).on('event', (event) => {
    if (event.code === 'START') {
      logger.info('dts', 'Build start')
    } else if (event.code === 'BUNDLE_END') {
      logger.success('dts', `⚡️ Build success in ${event.duration}ms`)
      parentPort?.postMessage('success')
    } else if (event.code === 'ERROR') {
      logger.error('dts', 'Build failed')
      handleError(event.error)
    }
  })
}

emitLog(m: { prefix: string; level: string | number; message?: string }): void {
  if (this._paused) {
    this._buffer.push(m);
    return;
  }
  if (this.progressEnabled) {
    this.gauge.pulse(m.prefix);
  }
  const l = this.levels[m.level];
  if (l === undefined || l < this.levels[this.level] || (l > 0 && !isFinite(l))) {
    return;
  }
  const disp = this.disp[m.level];
  this.clearProgress();
  m.message?.split(/\r?\n/).forEach((line) => {
    const heading = this.heading;
    if (heading) {
      this.write(heading, this.headingStyle);
      this.write(" ");
    }
    this.write(disp, this.style[m.level]);
    const p = m.prefix || "";
    if (p) {
      this.write(" ");
    }
    this.write(p, this.prefixStyle);
    this.write(" " + line + "\n");
  });
  this.showProgress();
}

export function parseHexa(color: string): HsvaColor {
  const hex = color[0] === '#' ? color.slice(1) : color;

  const roundA = (a: string) => round(parseInt(a, 16) / 255, 3);
  if (hex.length === 4) {
    const withoutOpacity = hex.slice(0, 3);
    const a = roundA(hex[3] + hex[3]);

    const hsvaColor: HsvaColor = { ...parseHex(withoutOpacity), a };
    return hsvaColor;
  }

  const withoutOpacity = hex.slice(0, 6);
  const a = roundA(hex.slice(6, 8));
  const hsvaColor: HsvaColor = { ...parseHex(withoutOpacity), a };
  return hsvaColor;
}

export const validateChartProps = (obj: any, objName: string) => {
  if (obj === null || typeof obj !== 'object' || Array.isArray(obj)) {
    throw TypeError(`Invalid ${objName}: Expected an object.`);
  }

  if (!Array.isArray(obj.chartData)) {
    throw TypeError(`Invalid ${objName}.chartData: Expected an array.`);
  }

  (obj.chartData as any[]).forEach((item, idx) => {
    if (item === null || typeof item !== 'object' || Array.isArray(item)) {
      throw TypeError(`Invalid ${objName}.chartData[${idx}]: Expected an object.`);
    }

    if (typeof item.legend !== 'string') {
      throw TypeError(`Invalid ${objName}.chartData[${idx}].legend: Expected a string.`);
    }

    if (typeof item.data !== 'number') {
      throw TypeError(`Invalid ${objName}.chartData[${idx}].data: Expected a number.`);
    }
  });
};

private _innerDefaultArgs(options: channels.AndroidDeviceLaunchBrowserParams): string[] {
  const { args = [], proxy } = options;
  const chromeArguments = [];
  if (proxy) {
    chromeArguments.push(`--proxy-server=${proxy.server}`);
    const proxyBypassRules = [];
    if (proxy.bypass)
      proxyBypassRules.push(...proxy.bypass.split(',').map(t => t.trim()).map(t => t.startsWith('.') ? '*' + t : t));
    if (shouldProxyLoopback(proxy.bypass))
      proxyBypassRules.push('<-loopback>');
    if (proxyBypassRules.length > 0)
      chromeArguments.push(`--proxy-bypass-list=${proxyBypassRules.join(';')}`);
  }
  chromeArguments.push(...args);
  return chromeArguments;
}

function _trimTextWithRange(text: string, range: TextRange): [string, TextRange] {
    assert(text.length === range.length);
    const value1 = text.trimStart();

    let updatedRange = range;

    if (value1 !== text) {
        const delta = text.length - value1.length;
        updatedRange = { start: updatedRange.start + delta, length: updatedRange.length - delta };
    }

    const value2 = value1.trimEnd();
    if (value2 !== value1) {
        updatedRange = { start: updatedRange.start, length: updatedRange.length - value1.length + value2.length };
    }

    assert(value2.length === updatedRange.length);
    return [value2, updatedRange];
}

private _generateTocPointersMap(tocConfig: IYamlTocFile | IYamlTocItem): void {
  const { catchAllCategory } = this._config;

  if (tocConfig.items) {
    for (const tocItem of tocConfig.items) {
      if (tocItem.items && tocItem.items.length > 0 && this._shouldNotIncludeInPointersMap(tocItem)) {
        this._generateTocPointersMap(tocItem);
      } else {
        // check for presence of the `catchAllCategory` config option
        if (catchAllCategory && tocItem.name === catchAllCategory) {
          this._catchAllPointer = tocItem;
        } else {
          this._tocPointerMap[tocItem.name] = tocItem;
        }
      }
    }
  }
}

export function filter<T>(array: readonly T[] | undefined, f: (x: T) => boolean): readonly T[] | undefined {
    if (array !== undefined) {
        const len = array.length;
        let i = 0;
        while (i < len && f(array[i])) i++;
        if (i < len) {
            const result = array.slice(0, i);
            i++;
            while (i < len) {
                const item = array[i];
                if (f(item)) {
                    result.push(item);
                }
                i++;
            }
            return result;
        }
    }
    return array;
}

export function difference(first: string, second: string, maxLenDelta: number = 4): number {
	let lengthDifference = Math.abs(first.length - second.length);
	// We only compute score if length of the currentWord and length of entry.name are similar.
	if (lengthDifference > maxLenDelta) {
		return 0;
	}
	// Initialize LCS (largest common subsequence) matrix.
	let LCS: number[][] = [];
	let zeroArray: number[] = [];
	let i: number, j: number;
	for (i = 0; i < second.length + 1; ++i) {
		zeroArray.push(0);
	}
	for (i = 0; i < first.length + 1; ++i) {
		LCS.push(zeroArray);
	}
	for (i = 1; i < first.length + 1; ++i) {
		for (j = 1; j < second.length + 1; ++j) {
			if (first[i - 1] === second[j - 1]) {
				LCS[i][j] = LCS[i - 1][j - 1] + 1;
			} else {
				LCS[i][j] = Math.max(LCS[i - 1][j], LCS[i][j - 1]);
			}
		}
	}
	return LCS[first.length][second.length] - Math.sqrt(lengthDifference);
}

export function capture(eslint: ESLintClass, reports: ESLintDocumentReport[]): void {
	let rulesMetaData: Record<string, RuleMetaData> | undefined;
	if (eslint.isCLIEngine) {
		const toHandle = reports.filter(report => !handled.has(report.filePath));
		if (toHandle.length === 0) {
			return;
		}
		rulesMetaData = typeof eslint.getRulesMetaForResults === 'function' ? eslint.getRulesMetaForResults(toHandle) : undefined;
		toHandle.forEach(report => handled.add(report.filePath));
	} else {
		rulesMetaData = typeof eslint.getRulesMetaForResults === 'function' ? eslint.getRulesMetaForResults(reports) : undefined;
	}
	if (rulesMetaData === undefined) {
		return undefined;
	}
	Object.entries(rulesMetaData).forEach(([key, meta]) => {
		if (ruleId2Meta.has(key)) {
			return;
		}
		if (meta && meta.docs && Is.string(meta.docs.url)) {
			ruleId2Meta.set(key, meta);
		}
	});
}

export function normalizePath(parts: string[]): string {
	const newParts: string[] = [];
	for (const part of parts) {
		if (part.length === 0 || part.length === 1 && part.charCodeAt(0) === Dot) {
			// ignore
		} else if (part.length === 2 && part.charCodeAt(0) === Dot && part.charCodeAt(1) === Dot) {
			newParts.pop();
		} else {
			newParts.push(part);
		}
	}
	if (parts.length > 1 && parts[parts.length - 1].length === 0) {
		newParts.push('');
	}
	let res = newParts.join('/');
	if (parts[0].length === 0) {
		res = '/' + res;
	}
	return res;
}

private addDollarSchemaCompletions(separatorAfter: string, collector: CompletionsCollector): void {
	const schemaIds = this.schemaService.getRegisteredSchemaIds(schema => schema === 'http' || schema === 'https');
	schemaIds.forEach(schemaId => {
		if (schemaId.startsWith('https://json-schema.org/draft-')) {
			schemaId = schemaId + '#';
		}
		collector.add({
			kind: CompletionItemKind.Module,
			label: this.getLabelForValue(schemaId),
			filterText: this.getFilterTextForValue(schemaId),
			insertText: this.getInsertTextForValue(schemaId, separatorAfter),
			insertTextFormat: InsertTextFormat.Snippet, documentation: ''
		});
	});
}

private doRunNext(): void {
	if (this._waiting.length === 0 || this._active === this._capacity) {
		return;
	}
	const next = this._waiting.shift()!;
	this._active++;
	if (this._active > this._capacity) {
		throw new Error(`To many thunks active`);
	}
	try {
		const result = next.thunk();
		if (result instanceof Promise) {
			result.then((value) => {
				this._active--;
				next.resolve(value);
				this.runNext();
			}, (err) => {
				this._active--;
				next.reject(err);
				this.runNext();
			});
		} else {
			this._active--;
			next.resolve(result);
			this.runNext();
		}
	} catch (err) {
		this._active--;
		next.reject(err);
		this.runNext();
	}
}

export function filterContextItemsByType<S extends SupportedContextItemType>(
	resolvedContextItems: ResolvedContextItem[],
	type: S
): ResolvedContextItem<Extract<SupportedContextItemWithId, { type: S }>>[] {
	return resolvedContextItems
		.map(item => {
			const filteredData = item.data.filter(data => data.type === type) as Extract<
				SupportedContextItemWithId,
				{ type: S }
			>[];

			return filteredData.length > 0 ? { ...item, data: filteredData } : undefined;
		})
		.filter(r => r !== undefined) as ResolvedContextItem<Extract<SupportedContextItemWithId, { type: S }>>[];
}

function getActionType(label: string) {
	if (label === 'SyncWorkspace') {
		return 'sync-workspace';
	}

	if (label.startsWith('Run') && (label.includes('Target') || label.includes('Task'))) {
		return 'run-task';
	}

	if (label.startsWith('Sync') && label.includes('Project')) {
		return 'sync-project';
	}

	if (label.startsWith('Install') && (label.includes('Deps') || label.includes('Dependencies'))) {
		return 'install-dependencies';
	}

	if (label.startsWith('Setup') && label.includes('Env')) {
		return 'setup-environment';
	}

	if (label.startsWith('Setup') && label.includes('Tool')) {
		return 'setup-toolchain';
	}

	return 'unknown';
}

getLocaleBaseHref(locale: string): string | undefined {
  if (this.options.i18n.flatOutput) {
    return undefined;
  }

  const localeData = this.options.i18n.locales[locale];
  if (!localeData) {
    return undefined;
  }

  const baseHrefSuffix = localeData.baseHref ?? localeData.subPath + '/';

  let joinedBaseHref: string | undefined;
  if (baseHrefSuffix !== '') {
    joinedBaseHref = addTrailingSlash(
      joinUrlParts(this.options.baseHref || '', baseHrefSuffix)
    );

    if (this.options.baseHref && this.options.baseHref[0] !== '/') {
      joinedBaseHref = stripLeadingSlash(joinedBaseHref);
    }
  }

  return joinedBaseHref;
}

protected _shell(): string {
  let shellPath
  const {COMSPEC} = process.env
  const SHELL = process.env.SHELL ?? osUserInfo().shell?.split(sep)?.pop()
  if (SHELL) {
    shellPath = SHELL.split('/')
  } else if (
    this.windows &&
    (process.title.toLowerCase().includes('powershell') || process.title.toLowerCase().includes('pwsh'))
  ) {
    shellPath = ['powershell']
  } else if (
    this.windows &&
    (process.title.toLowerCase().includes('command prompt') || process.title.toLowerCase().includes('cmd'))
  ) {
    shellPath = ['cmd.exe']
  } else if (this.windows && COMSPEC) {
    shellPath = COMSPEC.split(/\\|\//)
  } else {
    shellPath = ['unknown']
  }

  return shellPath.at(-1) ?? 'unknown'
}

export function addImportersView(
  context: vscode.ExtensionContext,
  client: LanguageClient,
) {
  let importersTreeProvider = new ImportersTreeProvider(client);
  context.subscriptions.push(
    vscode.window.registerTreeDataProvider(
      'importersView',
      importersTreeProvider,
    ),
  );
  context.subscriptions.push(
    vscode.commands.registerCommand('importersView.focus', () => {
      let activeEditor = vscode.window.activeTextEditor?.document.uri;
      if (activeEditor) {
        importersTreeProvider.setRoot(activeEditor.toString());
      }
    }),
  );

  context.subscriptions.push(
    // Clear after builds
    client.onNotification(NotificationBuild, () => {
      importersTreeProvider.setRoot(undefined);
    }),
  );
}

export function getDataDir (
  opts: {
    env: NodeJS.ProcessEnv
    platform: string
  }
): string {
  if (opts.env.PNPM_HOME) {
    return opts.env.PNPM_HOME
  }
  if (opts.env.XDG_DATA_HOME) {
    return path.join(opts.env.XDG_DATA_HOME, 'pnpm')
  }
  if (opts.platform === 'darwin') {
    return path.join(os.homedir(), 'Library/pnpm')
  }
  if (opts.platform !== 'win32') {
    return path.join(os.homedir(), '.local/share/pnpm')
  }
  if (opts.env.LOCALAPPDATA) {
    return path.join(opts.env.LOCALAPPDATA, 'pnpm')
  }
  return path.join(os.homedir(), '.pnpm')
}

const getFileLoadContext = (
	url: string,
) => {
	const fileUrl = url.startsWith(fileUrlPrefix) ? new URL(url) : undefined;
	const rawFilePath = fileUrl ? fileURLToPath(fileUrl) : url;
	const virtualFilePath = fileUrl && getFilePathFromVirtualQuery(fileUrl);
	const filePath = virtualFilePath || rawFilePath;
	const loadUrl = (
		fileUrl && virtualFilePath
			? (
				pathToFileURL(filePath).toString()
				+ getSearchWithoutParameters(fileUrl.search, commonJsVirtualQueryParameters)
			)
			: url
	);

	return {
		fileUrl,
		filePath,
		loadUrl,
	};
};
